import { ScaleTime } from 'd3-scale';
import { isUndefined } from 'lodash-es';

import { useGridPlotSize } from '../../chart-grid/hooks/useGridPlotSize.js';
import { VerticalCrosshair } from '../../crosshair/VerticalCrosshair.js';
import { useSynchronizedCrosshair } from '../hooks/useSynchronizedCrosshair.js';
import { containerSVG } from '../SharedChartInteractions.sty.js';

type VerticalSyncedCrosshairProps = {
  scale: ScaleTime<number, number>;
};

export const VerticalSynchronizedCrosshair = ({
  scale,
}: VerticalSyncedCrosshairProps) => {
  const { height } = useGridPlotSize();
  const syncedCrosshair = useSynchronizedCrosshair();

  if (!syncedCrosshair || isUndefined(syncedCrosshair.hoveredTimestamp)) {
    return null;
  }

  const x = scale(syncedCrosshair.hoveredTimestamp);

  return (
    <svg className={containerSVG}>
      <VerticalCrosshair x={x} height={height} dashed={true} />
    </svg>
  );
};

VerticalSynchronizedCrosshair['displayName'] = 'VerticalSynchronizedCrosshair';
